cmn_map_page.script:
// Fetch active Loaner Requests where Requested For has both city and country populated
const gr = new GlideRecord('x_cdltd_loaner_r_0_loaner_request');
gr.addEncodedQuery("active=true^requested_for.cityISNOTEMPTY^requested_for.countryISNOTEMPTY");
gr.orderBy('number');
gr.query();

while (gr.next()) {
    let location = gr.requested_for.city;

    // As country is a choice list, fetch the corresponding label
    const grCountry = new GlideRecord('sys_choice');
    grCountry.addQuery('name', 'sys_user');
    grCountry.addQuery('element', 'country');
    grCountry.addQuery('language', 'en');
    grCountry.addQuery('value', gr.requested_for.country);
    grCountry.query();

    if (grCountry.next()) location = gr.requested_for.city + ", " + grCountry.label;
    gs.debug('Requested For Locations: location = ' + location);

    try {
        const r = new sn_ws.RESTMessageV2('x_cdltd_loaner_r_0.Location to Lat & Long', 'Default GET');
        // r.setStringParameterNoEscape('text', 'Cape Town, South Africa');
        r.setStringParameterNoEscape('text', location);

        const response = r.execute();
        const httpStatus = response.getStatusCode();
        gs.debug('Requested For Locations: httpStatus = ' + httpStatus);
        if (200 <= httpStatus && httpStatus < 300) {
            // Extract latitude and longitude values from REST Message response in JSON format
            const responseBody = response.getBody();
            gs.debug('Requested For Locations: responseBody = ' + responseBody);
            const responseJSON = JSON.parse(responseBody);
            const { lat, lon } = responseJSON.features[0].properties;
            gs.info('Requested For Locations: location -> lat, lon = ' + location + ' -> ' + lat + ', ' + lon);

            // Plot each Location Request by Requested For's city -> coordinates
            const plot = map.addItem(gr);
            plot.latitude = '' + lat;
            plot.longitude = '' + lon;
            plot.dialog_title = gr.getDisplayValue();
            plot.icon = "https://maps.google.com/mapfiles/ms/micons/yellow.png";
            plot.icon_width = "32";
            plot.icon_height = "32";
        }
    } catch (xp) {
        gs.error('Requested For Locations: ' + xp);
    }
}
